651→                    if crate::float_probe::executions_agree(float_result, floor_result) {
652→                        agreements += 1;
653→                    } else if let Some(v) = float_inputs.get(idx).and_then(|v| v.as_f64()) {
654→                        divergent_values.push(v);
655→                    }
656→
657→                    raw_results.push((float_inputs.clone(), (**float_result).clone()));
658→                }
659→            }
660→
661→            let classification = crate::float_probe::classify(
662→                agreements,
663→                total_probes,
664→                crate::float_probe::AGREEMENT_THRESHOLD,
665→            );
666→            float_probe_results.push(crate::float_probe::FloatProbeResult {
667→                param_index: idx,
668→                param_name: analysis.params[idx].name.clone(),
669→                classification,
670→                agreements,
671→                total_probes,
672→                divergent_values,
673→            });
